add_action( 'wp', function () {
    if ( ! is_single() || get_post_type() !== 'post' ) {
        return;
    }
    add_filter( 'hooked_block_types', function( $hooks ) {
        $hooks['core/post-title'][] = array(
            'blockName'  => 'core/paragraph',
            'attributes' => array( 'content' => 'Hooked CTA' ),
            'position'   => 'after',
        );
        return $hooks;
    } );
} );
